namespace BlazorApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _sampleMessages =
    [
        "Your order has been shipped",
        "New comment on your post",
        "System maintenance scheduled",
        "You have a new follower",
        "Payment received successfully",
        "Your subscription is expiring soon",
        "New feature available: Dark Mode",
        "Weekly report is ready"
    ];

    /// <summary>
    /// Returns the initial set of notifications (used during prerender and first load).
    /// </summary>
    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        var notifications = new List<Notification>();
        for (int i = 0; i < 3; i++)
        {
            notifications.Add(new Notification
            {
                Id = _nextId++,
                Message = _sampleMessages[i],
                Timestamp = DateTime.UtcNow.AddMinutes(-10 + i)
            });
        }
        return Task.FromResult(notifications);
    }

    /// <summary>
    /// Simulates checking for new notifications. Randomly returns 0-1 new notifications.
    /// </summary>
    public Task<List<Notification>> CheckForNewNotificationsAsync()
    {
        var results = new List<Notification>();
        if (Random.Shared.Next(3) == 0) // ~33% chance of a new notification
        {
            results.Add(new Notification
            {
                Id = _nextId++,
                Message = _sampleMessages[Random.Shared.Next(_sampleMessages.Length)],
                Timestamp = DateTime.UtcNow
            });
        }
        return Task.FromResult(results);
    }
}

