@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@(Notifications?.Count ?? 0)</span></h1>

@if (Notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (Notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in Notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                <span>@notification.Message</span>
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? Notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not restored from persisted prerender state
        Notifications ??= await NotificationSvc.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during prerender, so this only
            // fires once the page is live and interactive in the browser.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                var newItems = await NotificationSvc.CheckForNewNotificationsAsync();
                if (newItems.Count > 0)
                {
                    Notifications ??= [];
                    Notifications.InsertRange(0, newItems);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

